mapper.select:
select sum(sei.lump_sum_wage) as lump_sum_wage, sum(sei.post_skill_salary) as post_skill_salary, sum(sei.target_performance_pay) as target_performance_pay, sum(sei.base_pay) as base_pay, sum(sei.post_subsidy) as post_subsidy, sum(sei.seniority_allowance) as seniority_allowance, sum(sei.transportation_allowance) as transportation_allowance, sum(sei.one_child_subsidy) as one_child_subsidy, sum(sei.personal_deductibles) as personal_deductibles, sum(sei.company_deductibles) as company_deductibles, sum(sei.personal_deduct_accumulation_fund) as personal_deduct_accumulation_fund, sum(sei.company_deduct_accumulation_fund) as company_deduct_accumulation_fund, sum(sei.safety_accumulation_award) as safety_accumulation_award, sum(sei.high_temperature_subsidy) as high_temperature_subsidy from swm_employee_interface sei where sei.data_status = 'T'
and sei.work_card in (
right(replicate('0',6) + convert(varchar(6),#{item}),6)
)
and sei.group_id in (
#{groupId}
)
